        <div class="overflow-x-auto mb-4"><table class="w-full text-sm border-collapse"><thead><tr class="bg-slate-100 text-left"><th class="px-4 py-2 border border-slate-200 font-semibold text-slate-700">特性</th><th class="px-4 py-2 border border-slate-200 font-semibold text-slate-700">GDScript (Godot)</th><th class="px-4 py-2 border border-slate-200 font-semibold text-slate-700">C# (Unity)</th><th class="px-4 py-2 border border-slate-200 font-semibold text-slate-700">Blueprint (Unreal)</th></tr></thead><tbody class="text-slate-600">
          <tr><td class="px-4 py-2 border border-slate-200 font-medium">语法风格</td><td class="px-4 py-2 border border-slate-200">Python-like（缩进、无分号）</td><td class="px-4 py-2 border border-slate-200">C 风格（花括号、分号）</td><td class="px-4 py-2 border border-slate-200">可视化节点连线</td></tr>
